module RefModule (
    input clk,
    input sreset,
    input load,
    input [7:0] reset_value,
    input [7:0] data,
    output [7:0] q );reg [7:0] q_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (sreset)
        q_reg <= reset_value;
    else if (load)
        q_reg <= data;
end

assign q = q_reg;

endmodule
